class Solution:
    def findErrorNums(self, nums):
        n = len(nums)
        dup = -1
        for v in range(1, n + 1):
            cnt = 0
            for x in nums:
                if x == v:
                    cnt += 1
            if cnt == 2:
                dup = v
            elif cnt == 0:
                missing = v
        return [dup, missing]

