class Solution:
    def findErrorNums(self, nums):
        from collections import Counter
        cnt = Counter(nums)
        n = len(nums)
        dup = missing = -1
        for v in range(1, n + 1):
            c = cnt.get(v, 0)
            if c == 2:
                dup = v
            elif c == 0:
                missing = v
        return [dup, missing]

