var findErrorNums = function(nums) {
    const n = nums.length;
    const cnt = new Array(n + 1).fill(0);
    for (const x of nums) cnt[x]++;
    let dup = -1, missing = -1;
    for (let v = 1; v <= n; v++) {
        if (cnt[v] === 2) dup = v;
        else if (cnt[v] === 0) missing = v;
    }
    return [dup, missing];
};
